mapper.select:
SELECT a.item_cd AS itemCd, a.item_name AS itemName, a.item_type_cd AS itemTypeCd, a.storage_cd AS storageCd, SUM(isnull(a.qty, 0)) AS qty FROM vw_inv_stock_tran a where a.tran_date <= #{stdDate}
AND a.item_cd LIKE '%' + #{itemCd} + '%'
AND a.item_name LIKE '%' + #{itemName} + '%'
AND a.item_type_cd = #{itemTypeCd}
GROUP BY a.item_cd, a.item_name, a.item_type_cd, a.storage_cd HAVING SUM(a.qty) != 0 ORDER BY a.item_cd, a.storage_cd

select dbo.getCommonName('area', a.area_cd) as areaName ,b.storage_name ,a.scale_nickname as scaleNickname ,a.scale_cd ,a.scale_name ,a.etc ,a.scale_id from tb_scale_mst a left outer join tb_storage_mst b --inner join tb_storage_mst b on b.storage_cd = a.storage_cd where 1=1
AND a.use_yn = #{useYn}
AND a.area_cd = #{areaCd}
AND a.storage_cd = #{storageCd}
AND a.scale_nickname LIKE '%' + #{scaleNickname} + '%'
order by a.area_cd

with work_main as ( select a.prod_date , b.make_no , a.item_cd , c.item_name , a.order_qty , c.unit , a.work_proc_id , a.proc_cd from TB_WORK_ORDER_PROC a inner join TB_WORK_ORDER_BATCH b on b.work_batch_id = a.work_batch_id inner join tb_item_mst c on c.item_cd = a.item_cd where a.prod_date between #{strDate} and #{endDate} and a.proc_cd != 'PRC002'
and a.proc_cd = #{procCd}
), prod_info as ( select b.item_cd , sum(b.use_qty) as qty , a.work_proc_id from tb_prod_info a inner join tb_prod_use b on b.prod_info_id = a.prod_info_id group by b.item_cd, a.work_proc_id ), weigh_info as ( select b.item_cd , sum(b.weigh_qty) as qty , a.work_proc_id from tb_weigh_info a inner join tb_weigh_inv b on b.weigh_id = a.weigh_id group by b.item_cd, a.work_proc_id ) select a.prod_date , a.make_no , a.item_cd , a.item_name , a.order_qty , a.unit , d.item_cd as bom_item_cd , d.item_name as bom_item_name , d.spec , case when a.proc_cd in ('PRC001', 'PRC002') then isnull(e.qty, 0) else isnull(f.qty, 0) end as qty from work_main a inner join tb_bom_mst b on a.item_cd = b.item_cd and b.default_yn = 'Y' inner join tb_bom_recipe c on b.bom_id = c.bom_id inner join tb_item_mst d on d.item_cd = c.item_cd left join weigh_info e on e.item_cd = d.item_cd and e.work_proc_id = a.work_proc_id left join prod_info f on f.item_cd = d.item_cd and f.work_proc_id = a.work_proc_id order by a.prod_date desc, a.item_cd, a.make_no desc, d.item_cd

select a.item_cd ,b.item_name ,a.expiry_date ,a.test_no ,DATEDIFF(DAY, #{stdDate}, a.expiry_date) AS remain_day ,c.storage_cd ,c.qty from tb_item_test_no a inner join tb_item_mst b on b.item_cd = a.item_cd inner join vw_inv_stock_tran c on c.test_no = a.test_no where a.item_type_cd = 'M1' and a.expiry_date between #{strDate} and #{endDate}
and a.area_cd = #{areaCd}
AND a.item_cd LIKE '%' + #{itemCd} + '%'
AND b.item_name LIKE '%' + #{itemName} + '%'

WITH qty AS ( SELECT b.item_cd, SUM(CASE WHEN a.tran_type_cd = 'A' THEN b.qty ELSE 0 END) AS a_qty, SUM(CASE WHEN a.tran_type_cd = 'E' THEN b.qty ELSE 0 END) AS e_qty, SUM(CASE WHEN a.tran_type_cd = 'P' THEN b.qty ELSE 0 END) AS p_qty, SUM(CASE WHEN a.tran_type_cd = 'R' THEN b.qty ELSE 0 END) AS r_qty, SUM(CASE WHEN a.tran_type_cd = 'T' THEN b.qty ELSE 0 END) AS t_qty, SUM(CASE WHEN a.tran_type_cd = 'Q' THEN b.qty ELSE 0 END) AS q_qty, SUM(CASE WHEN a.tran_type_cd = 'S' THEN b.qty ELSE 0 END) AS s_qty, SUM(CASE WHEN a.tran_type_cd = 'V' THEN b.qty ELSE 0 END) AS v_qty, SUM(CASE WHEN a.tran_type_cd = 'W' THEN b.qty ELSE 0 END) AS w_qty, SUM(CASE WHEN a.tran_type_cd = 'X' THEN b.qty ELSE 0 END) AS x_qty, SUM(CASE WHEN a.tran_type_cd = 'U' THEN b.qty ELSE 0 END) AS u_qty FROM tb_inv_tran_mst a INNER JOIN tb_inv_tran_item b ON a.tran_id = b.tran_id WHERE b.item_type_cd = #{itemTypeCd} AND a.tran_date BETWEEN #{strDate} AND #{endDate}
AND b.item_cd LIKE '%' + #{itemCd} + '%'
GROUP BY b.item_cd ) SELECT a.item_cd, ISNULL(c.code_nm, '') AS order_type, a.item_name, b.code_nm AS item_type_name, d.customer_name, ISNULL(a.in_price, 0) AS in_price, ISNULL(q.a_qty, 0) AS as_qty, ISNULL(q.e_qty, 0) AS es_qty, ISNULL(q.p_qty, 0) AS ps_qty, ISNULL(q.r_qty, 0) AS rs_qty, ISNULL(q.t_qty, 0) AS ts_qty, ISNULL(q.q_qty, 0) AS qs_qty, ISNULL(q.s_qty, 0) AS ss_qty, ISNULL(q.v_qty, 0) AS vs_qty, ISNULL(q.w_qty, 0) AS ws_qty, ISNULL(q.x_qty, 0) AS xs_qty, ISNULL(q.u_qty, 0) AS us_qty, ISNULL(q.a_qty, 0)*ISNULL(a.in_price, 0) as asAmt, ISNULL(q.e_qty, 0)*ISNULL(a.in_price, 0) as esAmt FROM tb_item_mst a INNER JOIN tb_common_code b ON b.com_type_cd = 'item_type_cd' AND b.code = a.item_type_cd LEFT JOIN tb_common_code c ON c.com_type_cd = 'ITEM_GRP1' AND c.code = a.item_grp1 LEFT JOIN tb_customer d ON d.customer_cd = a.customer_cd LEFT JOIN qty q ON q.item_cd = a.item_cd WHERE a.item_type_cd = #{itemTypeCd}
AND a.item_cd LIKE '%' + #{itemCd} + '%'
AND a.item_name LIKE '%' + #{itemName} + '%'
AND c.code LIKE '%' + #{itemGrp1} + '%'
